const forecast = $('Build Forecast Dataset').first().json;
const aiOutput = $('Demand Forecast Agent').first().json.output || '';

return [{
  json: {
    report_date: forecast.report_date,
    total_products: forecast.total_products,
    critical_count: forecast.critical_count,
    low_stock_count: forecast.low_stock_count,
    reorder_count: forecast.reorder_count,
    ok_count: forecast.ok_count,
    critical_items: forecast.critical_items,
    low_stock_items: forecast.low_stock_items,
    reorder_items: forecast.reorder_items,
    all_products: forecast.all_products,
    summary_text: forecast.summary_text,
    ai_output: aiOutput,
    has_critical: forecast.critical_count > 0
  }
}];

const salesItems = $('Fetch Sales History').all();
const inventoryItems = $('Fetch Current Inventory').all();
const config = $('Set Forecast Configuration').first().json;

const salesByProduct = {};
for (const item of salesItems) {
  const s = item.json;
  const pid = s.product_id || s.SKU || s.sku;
  if (!pid) continue;
  if (!salesByProduct[pid]) salesByProduct[pid] = { sales_data: [], total_units: 0 };
  const units = parseFloat(s.units_sold || s.quantity || s.qty || 0);
  salesByProduct[pid].sales_data.push({ date: s.date, units });
  salesByProduct[pid].total_units += units;
}

const inventoryProducts = [];
for (const item of inventoryItems) {
  const inv = item.json;
  const pid = inv.product_id || inv.SKU || inv.sku;
  if (!pid) continue;

  const salesData = salesByProduct[pid] || { sales_data: [], total_units: 0 };
  const avgDailySales = salesData.total_units / (config.lookback_days || 90);
  const currentStock = parseFloat(inv.current_stock || inv.quantity || 0);
  const leadTime = parseFloat(inv.lead_time_days || 7);
  const reorderPoint = parseFloat(inv.reorder_point || (avgDailySales * leadTime * 1.5));
  const daysOfStock = avgDailySales > 0 ? Math.floor(currentStock / avgDailySales) : 999;
  const projectedStockout = avgDailySales > 0 ? new Date(Date.now() + daysOfStock * 86400000).toISOString().split('T')[0] : 'N/A';
  const reorderQty = Math.ceil(avgDailySales * (config.forecast_days || 30) * 1.2);

  let status = 'OK';
  if (daysOfStock <= config.critical_stock_threshold_days) status = 'CRITICAL';
  else if (daysOfStock <= config.low_stock_threshold_days) status = 'LOW';
  else if (currentStock <= reorderPoint) status = 'REORDER';

  inventoryProducts.push({
    product_id: pid,
    product_name: inv.product_name || inv.name || pid,
    current_stock: currentStock,
    avg_daily_sales: Math.round(avgDailySales * 100) / 100,
    days_of_stock: daysOfStock,
    projected_stockout_date: projectedStockout,
    reorder_quantity: reorderQty,
    reorder_point: Math.round(reorderPoint),
    lead_time_days: leadTime,
    unit_cost: parseFloat(inv.unit_cost || 0),
    supplier: inv.supplier || 'Unknown',
    status,
    sales_30d: Math.round(avgDailySales * 30),
    sales_90d: salesData.total_units
  });
}

inventoryProducts.sort((a, b) => a.days_of_stock - b.days_of_stock);

const critical = inventoryProducts.filter(p => p.status === 'CRITICAL');
const lowStock = inventoryProducts.filter(p => p.status === 'LOW');
const reorderNeeded = inventoryProducts.filter(p => p.status === 'REORDER');

return [{
  json: {
    report_date: config.report_date,
    total_products: inventoryProducts.length,
    critical_count: critical.length,
    low_stock_count: lowStock.length,
    reorder_count: reorderNeeded.length,
    ok_count: inventoryProducts.filter(p => p.status === 'OK').length,
    critical_items: critical,
    low_stock_items: lowStock,
    reorder_items: reorderNeeded,
    all_products: inventoryProducts,
    summary_text: inventoryProducts.slice(0, 20).map(p =>
      p.product_id + ' | ' + p.product_name + ' | Stock: ' + p.current_stock +
      ' | Days: ' + p.days_of_stock + ' | AvgDaily: ' + p.avg_daily_sales +
      ' | Stockout: ' + p.projected_stockout_date + ' | ' + p.status
    ).join('\n')
  }
}];

