const forecastData = $('Build Forecast Dataset').first().json;
const itemsToReorder = [
  ...(forecastData.critical_items || []),
  ...(forecastData.low_stock_items || []),
  ...(forecastData.reorder_items || [])
];

const seen = new Set();
const uniqueOrders = itemsToReorder.filter(item => {
  if (seen.has(item.product_id)) return false;
  seen.add(item.product_id);
  return true;
});

const purchaseOrders = uniqueOrders.map(item => ({
  po_number: 'PO-' + item.product_id + '-' + new Date().toISOString().split('T')[0].replace(/-/g,''),
  product_id: item.product_id,
  product_name: item.product_name,
  supplier: item.supplier,
  order_quantity: item.reorder_quantity,
  unit_cost: item.unit_cost,
  total_cost: Math.round(item.reorder_quantity * item.unit_cost * 100) / 100,
  priority: item.status,
  days_of_stock: item.days_of_stock,
  projected_stockout: item.projected_stockout_date,
  created_date: forecastData.report_date,
  status: 'PENDING_APPROVAL'
}));

const totalCost = purchaseOrders.reduce((sum, po) => sum + po.total_cost, 0);
return [{
  json: {
    purchase_orders: purchaseOrders,
    po_count: purchaseOrders.length,
    total_reorder_cost: Math.round(totalCost * 100) / 100,
    report_date: forecastData.report_date
  }
}];
